INSERT INTO `archetypes` VALUES
(1,'Mae de Familia','Mulher de 35-50 anos, pratica, carinhosa','Fala de forma carinhosa e pratica. Usa gente, meninas. Conta experiencias reais com filhos e marido.','Gente, to adorando! / meninas me ajudem / fiz pra toda familia',15,35,5,30,'mae1','2026-03-01 13:29:07'),
(2,'Nerd Fitness','Homem de 25-35 anos, obcecado com dados e macros','Fala com precisao cientifica. Cita estudos. Gosta de numeros e percentuais.','De acordo com um estudo / meu percentual de gordura / a ciencia mostra que',5,10,8,40,'nerd1','2026-03-01 13:29:07'),
(3,'Mano da Quebrada','Jovem de 18-28 anos, girias, informal, entusiasmado','Usa mano, cara, demais. Frases curtas. Muitos pontos de exclamacao.','mano que resultado!! / cara to chocado / funcionou demais',25,45,2,15,'mano1','2026-03-01 13:29:07'),
(4,'Nutricionista','Profissional da saude, 30-45 anos, didatica','Linguagem tecnica mas acessivel. Cuida para nao dar diagnostico.','Do ponto de vista nutricional / as evidencias indicam / consulte um profissional',3,15,10,45,'nutri1','2026-03-01 13:29:07'),
(5,'Vendedor de Rua','Pessoa animada, persuasiva, 28-45 anos','Entusiasta, muitas exclamacoes. Sempre descobriu o segredo de algo.','Descobri o segredo! / vale demais a pena / to te contando isso porque',20,40,3,20,'vend1','2026-03-01 13:29:07'),
(6,'Advogado','Profissional exigente, cetico, 35-50 anos','Questiona antes de aceitar. Analitico. Usa todavia, entretanto, cabe ressaltar.','Quais sao as evidencias? / cabe ressaltar que / todavia os resultados mostram',5,5,15,60,'adv1','2026-03-01 13:29:07');
INSERT INTO `blocks` VALUES
(1,1,'Dicas dos Nutricionistas','Nutricionista refinando aplicação avançada: corrigindo execução, ajustando estratégia, validando comportamentos, introduzindo micro melhorias. Não ensina o básico — presume domínio do protocolo.','running',NULL,'2026-03-04 02:32:05',1,1),
(2,1,'Resultados e Transformações','Relatos de progresso contínuo: ajuste de rotina, superação de dificuldade específica, comparação de evolução, confirmação de consistência. Comunidade já consolidada — sem euforia inicial, sem descoberta.','done',NULL,'2026-03-04 02:32:05',0,0),
(3,1,'Dúvidas de Praticantes','Interação técnica entre membros experientes: opinião técnica, dificuldade pontual, ajuste fino, debate de nuance. PROIBIDO: perguntas básicas, pedido de explicação estrutural, fingir desconhecimento do método.','done',NULL,'2026-03-04 02:32:05',0,0),
(4,1,'Egípcio vs Outras Dietas','Comparação entre o método e low carb, jejum, mediterrânea — feita por quem experimentou ambos','done',NULL,'2026-03-04 02:32:05',0,0),
(5,1,'Dicas Práticas do Protocolo','Hacks e dicas de membros experientes: café da manhã, marmita, sequência alimentar','done',NULL,'2026-03-04 02:32:05',0,0),
(6,1,'Valeu o Investimento?','Membros falando sobre custo vs resultado. Comparações com o que gastavam antes','done',NULL,'2026-03-04 02:32:05',0,0),
(7,1,'Primeiros 7 Dias — Surpresa Total','Relatos de quem está na primeira semana e ficou chocado com a velocidade do resultado','done',NULL,'2026-03-04 02:32:05',0,0),
(8,1,'Quem Tentou Tudo e Finalmente Conseguiu','Histórias de múltiplas tentativas fracassadas e como o protocolo foi diferente','done',NULL,'2026-03-04 02:32:05',0,0),
(9,1,'Homens Sem Camisa Novamente','Homens relatando a sensação de voltar à praia, piscina, tirar a camisa com confiança','done',NULL,'2026-03-04 02:32:05',0,0),
(10,1,'Mulheres e o Biquíni de Volta','Mulheres que voltaram a usar o biquíni guardado. Autoestima, roupas antigas, fotos','done',NULL,'2026-03-04 02:32:05',0,0),
(11,1,'Casais Que Começaram Juntos','Casais no protocolo. Resultados dos dois, apoio mútuo, quem está na frente','done',NULL,'2026-03-04 02:32:05',0,0),
(12,1,'Mães e a Família Toda','Mães que adaptaram o protocolo para a família inteira. Como fizeram, o que acharam','done',NULL,'2026-03-04 02:32:05',0,0),
(13,1,'O Inchaço Que Sumiu em Dias','Foco na desinflamação rápida. Roupas que voltaram a servir antes mesmo de perder muito peso','done',NULL,'2026-03-04 02:32:05',0,0),
(14,1,'Metabolismo Lento — Acabou a Desculpa','Pessoas que tinham essa crença e viram o protocolo funcionar de qualquer jeito','done',NULL,'2026-03-04 02:32:05',0,0),
(15,1,'Sem Academia, Sem Suplemento, Sem Fome','O diferencial: nenhum dos três. Resultado puro de alimentação na ordem certa','done',NULL,'2026-03-04 02:32:05',0,0),
(16,1,'Antes Eu Sofria de Fome, Agora Como','Contraste com dietas restritivas anteriores. A liberdade do protocolo vs o sofrimento de antes','done',NULL,'2026-03-04 02:32:05',0,0),
(17,1,'Quando Todo Mundo Começa a Perguntar','O momento em que colegas, vizinhos e família notam e perguntam o segredo','done',NULL,'2026-03-04 02:32:05',0,0),
(18,1,'R$29,90 — O Investimento Que Valeu Tudo','Foco no preço acessível e no contraste com outros métodos caros e sem resultado','done',NULL,'2026-03-04 02:32:05',0,0),
(19,1,'Acesso Vitalício — Para Sempre','Membros falando sobre ter acesso pra vida toda, consultar quando quiser, indicar amigos','done',NULL,'2026-03-04 02:32:05',0,0),
(20,1,'Acima de 50 — Funciona Igual','Pessoas mais velhas que acreditavam que a idade era obstáculo. Foram surpreendidas','done',NULL,'2026-03-04 02:32:05',0,0),
(21,1,'Protocolo Fora de Casa — Restaurante e Viagem','Como membros mantêm o protocolo comendo fora, viajando, em festas','done',NULL,'2026-03-04 02:32:05',0,0),
(22,1,'Resultados Extremos — Acima de 15kg','Foco nos casos de maior perda. Números, prazos, como fizeram','done',NULL,'2026-03-04 02:32:05',0,0),
(23,1,'O Médico Ficou Impressionado','Membros que levaram exames para o médico e ouviram elogios dos resultados','done',NULL,'2026-03-04 02:32:05',0,0),
(24,1,'Por Que Funciona — O Mecanismo','Discussão técnica sobre combinação alimentar, timing, glicemia. Por que é diferente','done',NULL,'2026-03-04 02:32:05',0,0),
(25,1,'Quem Estava Perto da Bariátrica','Membros com indicação de cirurgia que conseguiram com o protocolo','done',NULL,'2026-03-04 02:32:05',0,0),
(26,1,'A Fome Que Simplesmente Foi Embora','O espanto com a saciedade natural. Como o corpo regula a fome sozinho','done',NULL,'2026-03-04 02:32:05',0,0),
(27,1,'Roupas Antigas de Volta','O momento emocional de vestir uma peça guardada. Calças, vestidos, biquínis','done',NULL,'2026-03-04 02:32:05',0,0),
(28,1,'Virei Promotor — Já Indiquei 5 ou Mais','Membros que se tornaram divulgadores orgânicos e os resultados de quem indicaram','done',NULL,'2026-03-04 02:32:05',0,0),
(29,1,'O Café da Manhã Egípcio na Prática','O que comem, como preparam, quanto tempo leva, por que muda tudo','done',NULL,'2026-03-04 02:32:05',0,0),
(30,1,'Fibra → Proteína → Carbo — A Sequência','A lógica da ordem alimentar. Como e por que funciona no nível da glicemia','done',NULL,'2026-03-04 02:32:05',0,0),
(31,1,'Dia a Dia da Primeira Semana','Cronologia real: o que mudou do dia 1 ao dia 7 na percepção de membros','done',NULL,'2026-03-04 02:32:05',0,0),
