(33,1,'Diabetes e o Protocolo','Membros com diabetes que adaptaram com supervisão médica e viram melhora','done',NULL,'2026-03-04 02:32:05',0,0),
(34,1,'Sem Tempo Para Cozinhar — Como Resolve','Rotina intensa e protocolo. Marmitas, estratégias rápidas, o que funciona','done',NULL,'2026-03-04 02:32:05',0,0),
(35,1,'Convertido — Era Cético, Agora Indica','Quem resistiu muito antes de comprar e hoje é o maior defensor','done',NULL,'2026-03-04 02:32:05',0,0),
(36,1,'Pressão, Colesterol e Saúde Geral','Benefícios além do peso que apareceram como bônus do protocolo','done',NULL,'2026-03-04 02:32:05',0,0),
(37,1,'Família Inteira no Protocolo','Quando mais de um membro da família adota. Dinâmica, apoio, resultados coletivos','done',NULL,'2026-03-04 02:32:05',0,0),
(38,1,'A Garantia de 7 Dias — Quem Ficou','Membros que compraram na dúvida e nunca pediram reembolso. Por quê','done',NULL,'2026-03-04 02:32:05',0,0),
(39,1,'Voltei Após uma Pausa — Retomada Rápida','Quem parou por algum motivo e voltou. Como o corpo retomou rápido','done',NULL,'2026-03-04 02:32:05',0,0),
(40,1,'Marmita Fit Egípcia — Como Montar','A marmita perfeita do protocolo. O que colocar, como dividir, tempo de preparo','done',NULL,'2026-03-04 02:32:05',0,0),
(41,1,'Joelho Parou de Doer, Humor Melhorou','Efeitos colaterais positivos além do peso que surpreenderam os membros','done',NULL,'2026-03-04 02:32:05',0,0),
(42,1,'Low Carb Abandonado — Por Quê','Quem fazia low carb, sofria, e migrou para o método. O contraste real','done',NULL,'2026-03-04 02:32:05',0,0),
(43,1,'Jejum Que Desmaiei vs Protocolo Que Como','A comparação visceral de quem tentou jejum e não aguentou vs comer 3 vezes e emagrecer','done',NULL,'2026-03-04 02:32:05',0,0),
(44,1,'A Fome Nunca Voltou','A análise do por que a saciedade é natural e duradoura no protocolo','done',NULL,'2026-03-04 02:32:05',0,0),
