INSERT INTO `rooms` VALUES
(1,'Dieta Faraônica','dieta-faraonica','Comunidade oficial do método milenar que emagreceu os faraós','active','2026-03-04 02:32:05','2026-03-06 17:53:25',NULL,'Protocolo Egípcio — Dieta Faraônica','dietas','Não é o que você come — é a combinação e a ORDEM dos alimentos. Os mesmos que você já tem em casa. A Dieta Faraônica tem 3.000 anos de validação: uma civilização inteira dependia de corpos funcionais para sobreviver. Sem academia, sem suplemento, sem cortar nada. Você remove o bloqueio metabólico que as dietas modernas nunca encontraram.','Homens e mulheres entre 18 e 75 anos que já tentaram outras dietas sem sucesso duradouro.','6kg em 2 semanas','14 a 20kg em 30 dias','36kg em 60 dias','Inchaço some nos primeiros dias, roupas antigas voltam a servir, autoestima em alta, fome diminui naturalmente, mais disposição ao acordar, pressão arterial normaliza, dores articulares reduzem','3 a 7 dias — corpo mais leve, cintura mais fina, fome diminui','R$ 29,90','Vitalício — Acesso do Imperador','7 dias incondicional','[\"Já tentei de tudo e nunca funcionou\",\"Parece bom demais para ser verdade\",\"Tenho medo de começar e desistir de novo\",\"Não tenho força de vontade suficiente\",\"Está caro demais\",\"Não sei se vou usar o suficiente para valer\",\"Posso achar de graça no Google\",\"Os depoimentos parecem falsos\",\"Isso tem embasamento científico?\",\"A dieta vai ser muito restritiva\",\"Não tenho tempo para preparar as refeições\",\"E se eu não conseguir encontrar esses alimentos?\",\"Posso me machucar sem acompanhamento\",\"Tenho condições específicas (diabetes, tireoide)\",\"Vou começar depois das festas\",\"Deixa eu pensar mais um pouco\"]','[\"Você não falhou — usou as ferramentas erradas. Isso tem 3.000 anos, as dietas que tentou mal existem há 50.\",\"8.474 pessoas transformadas. 4.8 de nota. 98% satisfação. Garantia de 7 dias. Quem frauda não devolve dinheiro.\",\"Você não precisará de força de vontade porque não passará fome. Foi criado para quem precisava de energia máxima.\",\"Não depende de força de vontade. Depende da ordem certa dos alimentos. Remove o bloqueio, não força nada.\",\"Quanto gastou em dietas que não funcionaram? R$29,90 com acesso vitalício. O risco é nosso.\",\"O protocolo usa o que você já tem em casa. Sem preparo complexo, sem rotina rígida.\",\"Anos no Google nunca encontrará o protocolo completo. Online existem fragmentos. Aqui está o método inteiro.\",\"Nome, cidade, prazo específico em cada relato. Garantia de 7 dias. Quem fabrica depoimento não devolve dinheiro.\",\"Embasamento histórico: civilização que governou milênios com corpos funcionais sem academia.\",\"Saciedade e densidade nutricional. Você come arroz, fruta, ovo, frango. Nada cortado.\",\"Alimentos simples de qualquer mercado. 20 minutos de preparo semanal.\",\"Tudo em qualquer feira ou supermercado. Sem importado.\",\"Alimentos naturais, sem estimulantes. 8.474 pessoas sem intercorrência. Garantia de 7 dias.\",\"Para condições específicas: consulte seu médico antes como em qualquer mudança alimentar.\",\"Cada mês são 6 a 20kg que poderiam ter saído. O protocolo se adapta à sua rotina atual.\",\"7 dias de garantia incondicional. Você não está decidindo — está testando. Se não funcionar, recebe tudo de volta.\"]','medio','intensa','[1,2,3,4,5,6]',6,4,'[\"produto_nome\",\"produto_nicho\",\"produto_mecanismo\",\"produto_publico\",\"resultado_minimo\",\"resultado_medio\",\"resultado_maximo\",\"beneficios_secundarios\",\"primeiro_resultado_em\",\"oferta_preco\",\"oferta_acesso\",\"oferta_garantia\",\"objecoes\"]');
