(2118,6,NULL,5,NULL,'statement','Excelente iniciativa! A liderança também é sobre facilitar o acesso e a compreensão. Quem tiver materiais, compartilhe para o benefício de todos!',2117,19,12,'avancado',480,355,'2026-03-10 08:48:51','2026-03-05 16:14:56'),
